const inputBody = $('Webhook').item.json.body || {};
const script = inputBody.script || inputBody.scriptContent || inputBody.story_text || '';
const contentType = inputBody.content_type || 'ugc带货';

if (!script) {
  throw new Error('Missing script / scriptContent / story_text');
}

const itemIndex = 0;
const binaryPropertyName = 'data';

// 读取真正的二进制 buffer
const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, binaryPropertyName);

if (!buffer || !buffer.length) {
  throw new Error('参考图 buffer 为空，下载图片节点可能没有拿到文件');
}

// 取 binary 元信息
const item = $input.first();
const binaryMeta = item?.binary?.[binaryPropertyName] || {};

return {
  json: {
    story_text: script,
    person_image_b64: buffer.toString('base64'),
    person_mime_type: binaryMeta.mimeType || 'image/jpeg',
    content_type: contentType,
    taskId: inputBody.taskId || inputBody.task_id || inputBody.record_id || 'unknown_task',
    record_id: inputBody.record_id || '',
    table_link: inputBody.table_link || '',
    app_token: inputBody.app_token || '',
    table_id: inputBody.table_id || '',
    tenant_access_token: inputBody.tenant_access_token || '',
    api_key: inputBody.api_key || '',
    app_id: inputBody.app_id || '',
    app_secret: inputBody.app_secret || '',
    workflow_id: inputBody.workflow_id || 'flow_storyboard',
    imageUrl: inputBody.imageUrl || inputBody.referenceImage || ''
  }
};

function s(v){ return v == null ? '' : String(v); }
function stripDataPrefix(b64){ return s(b64).trim().replace(/^data:.*;base64,/, '').trim(); }

const j = $json || {};
const content_type = s(j.content_type).trim() || 'ugc带货';
const story_text = s(j.story_text).trim();
const person_mime_type = s(j.person_mime_type).trim() || 'image/jpeg';
const person_image_b64 = stripDataPrefix(j.person_image_b64);

if (!story_text) throw new Error('缺少 story_text（剧本为空）');
if (!person_image_b64) throw new Error('缺少 person_image_b64（参考图为空）');

const baseRules = [
  'You are a senior commercial storyboard director and prompt engineer.',
  'Your job is to convert the script and reference image into a 9-shot storyboard plan for a single 3x3 storyboard grid image.',
  'You must preserve identity consistency, outfit consistency, product consistency, and scene logic consistency.',
  'Return JSON only. No markdown. No explanation.',
  'shots must be exactly 9 items.',
  'Each shot must be visually distinct but remain coherent as one continuous story.',
  'Each shot is intended to later become an 8-second video shot, so each shot should already imply dynamic action potential.',
  'Do not output vague prompts. Be concrete and visual.',
  'No text overlays, no subtitles, no watermark, no UI.'
].join(' ');

const typeRulesMap = {
  'ugc带货': [
    'UGC commercial style.',
    'Phone-camera realism, natural motion logic, lifestyle feeling.',
    'The same person should naturally interact with the same product across the 9 shots.',
    'Environment should stay basically consistent unless script clearly requires a change.',
    'Keep authentic handheld-feel compositions and conversion-oriented story beats.'
  ].join(' '),
  '产品展示': [
    'Product showcase style.',
    'The product is always the hero.',
    'Use different framings, angles, detail focus, usage context, and hero beauty shots.',
    'Avoid empty catalog shots; keep cinematic realism.'
  ].join(' '),
  '剧情故事': [
    'Narrative storytelling style.',
    'Characters and props must remain continuous.',
    'Locations may evolve if the story requires, but continuity must be coherent.',
    'Each shot should feel like one beat in a short film storyboard.'
  ].join(' ')
};

const typeRules = typeRulesMap[content_type] || typeRulesMap['ugc带货'];

const outputSchema = {
  content_type: content_type,
  visual_anchor: {
    subject_identity: 'main character identity anchor from reference image',
    outfit_anchor: 'same outfit and accessories as reference image unless script explicitly changes',
    product_anchor: 'same product identity, same shape, color, logo, material',
    scene_anchor: 'same environment logic and lighting logic'
  },
  global_style: 'photorealistic, cinematic, rich details, realistic lighting, no text, no UI',
  negative_prompts: [
    'extra fingers',
    'deformed hands',
    'identity drift',
    'wrong product logo',
    'new accessories',
    'text overlay',
    'watermark',
    'frame border',
    'gridline',
    'cartoon look'
  ],
  shots: [
    {
      shot_index: 1,
      title: 'shot title',
      story_beat: 'what this beat does in the overall story',
      subject: 'who/what is the main subject in this shot',
      scene: 'where it happens',
      emotion: 'emotion or tone',
      camera_shot: 'composition / shot size / angle',
      motion_hint: 'what dynamic motion should later happen in video',
      prompt_text: 'detailed visual prompt for this panel'
    }
  ]
};

const instruction = `${baseRules}\n\nContent type rules: ${typeRules}\n\nScript:\n${story_text}\n\nReturn a JSON object following this structure exactly:\n${JSON.stringify(outputSchema, null, 2)}\n\nImportant hard constraints:\n1. shots must be exactly 9 items.\n2. shot_index must be 1 to 9.\n3. prompt_text must be detailed and visual, suitable for storyboard image generation.\n4. motion_hint must make later video expansion easy.\n5. Keep the same person, same outfit, same product, same scene logic unless the script explicitly changes it.\n6. No extra people unless the script explicitly requires them.\n7. No text elements in the frame.`;

const gemini_body = {
  contents: [
    {
      role: 'user',
      parts: [
        { text: instruction },
        {
          inline_data: {
            mime_type: person_mime_type,
            data: person_image_b64
          }
        }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.6,
    responseMimeType: 'application/json'
  }
};

return {
  json: {
    ...j,
    gemini_body
  }
};

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function extractFirstJsonObject(s) {
  if (!s) return '';
  const cleaned = String(s)
    .replace(/```json\s*/gi, '')
    .replace(/```/g, '')
    .trim();

  const start = cleaned.indexOf('{');
  if (start < 0) return '';

  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = start; i < cleaned.length; i++) {
    const ch = cleaned[i];

    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === '\\') {
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (!inString) {
      if (ch === '{') depth++;
      if (ch === '}') depth--;
      if (depth === 0) return cleaned.slice(start, i + 1).trim();
    }
  }
  return '';
}

function extractText(root) {
  const parts = root?.candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts) || parts.length === 0) return '';

  const p1 = parts.find(p => typeof p?.text === 'string' && p.text.trim().startsWith('{') && !p.thought);
  if (p1) return p1.text.trim();

  const p2 = parts.find(p => typeof p?.text === 'string' && p.text.trim().startsWith('{'));
  if (p2) return p2.text.trim();

  const all = parts.map(p => typeof p?.text === 'string' ? p.text : '').filter(Boolean).join('\n');
  return extractFirstJsonObject(all);
}

