const base = $('Prepare Gemini Data').first().json || {};
const story_text = s(base.story_text).trim();
const content_type = s(base.content_type).trim() || 'ugc带货';
const person_image_b64 = stripDataPrefix(base.person_image_b64);
const person_mime_type = s(base.person_mime_type).trim() || 'image/jpeg';

if (!person_image_b64) throw new Error('缺少参考图 person_image_b64');

const instruction = `You are a senior cinematic video prompt engineer.\n\nTask:\nExpand each of the 9 storyboard shots into a highly detailed 8-second video prompt.\n\nHard requirements:\n1. Do NOT rewrite the story structure.\n2. Keep the same person identity, outfit, accessories, product identity, and scene logic from the reference image and storyboard.\n3. Each shot duration is EXACTLY 8 seconds.\n4. For EACH shot output these fields:\n   - shot_index\n   - title\n   - story_beat\n   - subject\n   - scene\n   - emotion\n   - camera_shot\n   - motion_hint\n   - prompt_text\n   - start_frame\n   - action\n   - end_frame\n   - style\n   - timeline (minimum 4 segments)\n   - video_prompt\n5. The final video_prompt must strictly use this structure:\n   Start frame: ...\n   Action: ...\n   End frame: ...\n   Style: ...\n6. timeline must describe the exact 8-second evolution with time_range / visual / camera / environment.\n7. Maintain subject consistency and scene consistency throughout.\n8. Return JSON only. No markdown. No explanation.\n\nReturn schema example:\n{\n  \"content_type\": \"${content_type}\",\n  \"global_video_rules\": {\n    \"duration_per_shot\": 8,\n    \"subject_consistency\": true,\n    \"scene_consistency\": true,\n    \"style_anchor\": \"photorealistic, cinematic, realistic light, rich detail\"\n  },\n  \"shots\": [\n    {\n      \"shot_index\": 1,\n      \"title\": \"...\",\n      \"story_beat\": \"...\",\n      \"subject\": \"...\",\n      \"scene\": \"...\",\n      \"emotion\": \"...\",\n      \"camera_shot\": \"...\",\n      \"motion_hint\": \"...\",\n      \"prompt_text\": \"...\",\n      \"start_frame\": \"...\",\n      \"action\": \"...\",\n      \"end_frame\": \"...\",\n      \"style\": \"...\",\n      \"timeline\": [\n        {\n          \"time_range\": \"0.0-1.5s\",\n          \"visual\": \"...\",\n          \"camera\": \"...\",\n          \"environment\": \"...\"\n        },\n        {\n          \"time_range\": \"1.5-3.5s\",\n          \"visual\": \"...\",\n          \"camera\": \"...\",\n          \"environment\": \"...\"\n        },\n        {\n          \"time_range\": \"3.5-6.0s\",\n          \"visual\": \"...\",\n          \"camera\": \"...\",\n          \"environment\": \"...\"\n        },\n        {\n          \"time_range\": \"6.0-8.0s\",\n          \"visual\": \"...\",\n          \"camera\": \"...\",\n          \"environment\": \"...\"\n        }\n      ],\n      \"video_prompt\": \"Start frame: ... Action: ... End frame: ... Style: ...\"\n    }\n  ]\n}`;

const video_prompt_body = {
  contents: [
    {
      role: 'user',
      parts: [
        {
          text: instruction + '\n\nStory text:\n' + story_text + '\n\nStoryboard JSON:\n' + JSON.stringify(storyboard, null, 2)
        },
        {
          inline_data: {
            mime_type: person_mime_type,
            data: person_image_b64
          }
        }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.5,
    responseMimeType: 'application/json'
  }
};

return {
  json: {
    ...base,
    storyboard_json: storyboard,
    video_prompt_body
  }
};

