  const parts = root?.candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts) || parts.length === 0) return '';

  const p1 = parts.find(p => typeof p?.text === 'string' && p.text.trim().startsWith('{') && !p.thought);
  if (p1) return p1.text.trim();

  const p2 = parts.find(p => typeof p?.text === 'string' && p.text.trim().startsWith('{'));
  if (p2) return p2.text.trim();

  const all = parts.map(p => typeof p?.text === 'string' ? p.text : '').filter(Boolean).join('\n');
  return extractFirstJsonObject(all);
}

function getNodeFirstJson(name) {
  try {
    return $(name).first().json || {};
  } catch (e) {
    return {};
  }
}

// 关键：强制读取第一阶段“分析Agent-提示词撰写”的结果，而不是当前视频扩写结果
const firstStageRaw = getNodeFirstJson('分析Agent-提示词撰写');
const root = unwrapRoot(firstStageRaw);
const text = extractText(root);

if (!text) {
  throw new Error('第一阶段图片 storyboard 未返回可解析 JSON');
}

let plan;
try {
  plan = JSON.parse(text);
} catch (e) {
  throw new Error('第一阶段图片 storyboard JSON 解析失败：' + e.message + '\n原文前500字：' + String(text).slice(0, 500));
}

const shots = Array.isArray(plan?.shots) ? plan.shots : [];
if (shots.length !== 9) {
  throw new Error('第一阶段图片 storyboard shots 必须刚好 9 个；实际=' + shots.length);
}

const content_type = String(plan?.content_type || 'ugc带货');

const hardCommon =
`Create ONE single image. It must be a full-bleed 3x3 grid (nine panels) that fills the entire canvas with NO margins, NO borders, NO frames, NO gutters, NO gridlines, NO separators.
No visible text of any kind: no captions, no labels, no numbers, no watermark, no UI.
Photorealistic cinematic stills.
`;

const hardByType = {
  'ugc带货': `
Preserve EXACTLY the same number of people as the reference image across all panels. Do NOT add or remove any person.
Keep the SAME set of people across all panels. Keep EACH person's identity consistent (face, skin tone, hairstyle, outfit, accessories).
Keep the SAME product identity across all panels (same logo/label/color/material).
Keep a consistent UGC environment and lighting across all panels (phone-camera vibe, natural indoor light), only change camera angle/shot size and action beat.
`,
  '产品展示': `
Keep the SAME product identity across all panels (same logo/label/color/material). Product is the hero.
Background can be simple and consistent. Show different angles, macro details, usage steps, and hero shots.
Avoid pure catalog packshot; keep cinematic product photography.
`,
  '剧情故事': `
If the reference image contains multiple people, preserve EXACTLY the same number of people (do NOT add/remove).
Characters must stay consistent when they re-appear (face/outfit).
Locations MAY change between panels if the story requires it, but keep continuity coherent.
`
};

const hardLayout = hardCommon + (hardByType[content_type] || hardByType['ugc带货']);

const panels = shots.map((s, i) => {
  const p = String(s?.prompt_text || '').trim();
  if (!p) throw new Error('第 ' + (i + 1) + ' 个 shot 的 prompt_text 为空');
  return `Panel ${i + 1} (left-to-right, top-to-bottom): ${p}`;
}).join('\n\n');

const neg = Array.isArray(plan?.negative_prompts) ? plan.negative_prompts.join(', ') : '';
const negBlock = neg ? `\nNegative: ${neg}` : '';

return {
  json: {
    ...($json || {}),
    content_type,
    grid_prompt: `${hardLayout}${panels}${negBlock}`,
    grid_plan_json: plan,               // 图片分镜
    image_storyboard_json: plan         // 明确标记这是图片 storyboard
  }
};

function s(v){ return v == null ? '' : String(v); }
function stripDataPrefix(b64){ return s(b64).trim().replace(/^data:.*;base64,/, '').trim(); }

function getNodeFirstJson(name) {
  try {
    return $(name).first().json || {};
  } catch(e) {
    return {};
  }
}

const j = $json || {};

// 优先取当前输入；没有就回退到 Prepare Gemini Data
const prepare = getNodeFirstJson('Prepare Gemini Data');

const img_b64 = stripDataPrefix(j.person_image_b64) || stripDataPrefix(prepare.person_image_b64);
const img_mime = s(j.person_mime_type).trim() || s(prepare.person_mime_type).trim() || 'image/jpeg';

if (!img_b64) {
  throw new Error('缺少 person_image_b64。请从 “Download Reference Image → Prepare Gemini Data” 开始执行，或直接从 Webhook 执行整条流程。');
}

const gridNode = getNodeFirstJson('JSON转grid_prompt');
let promptText = s(j.grid_prompt).trim() || s(gridNode.grid_prompt).trim();

if (!promptText) {
  throw new Error('缺少 grid_prompt（请检查 JSON转grid_prompt 是否有输出）');
}

const CONSISTENCY_LOCK = `
ABSOLUTE CONSISTENCY LOCK (must follow):
- Preserve EXACTLY the same number of people as the reference image. Do NOT add or remove any person.
- Keep EXACTLY the same set of identities as the reference image (for EACH person): same face structure, eyes, nose, lips, skin tone, hairstyle, hair color, makeup.
- Keep EXACTLY the same outfit and accessories as the reference image (for EACH person): no new jewelry, no missing earrings, no changes in clothing texture or color.
- Keep EXACTLY the same core character design and props from the reference image.
- Do NOT swap hands, do NOT mirror/flip the image.
- Keep photorealistic cinematic stills.
- No text, no subtitles, no watermark, no UI, no borders, no frames, no gridlines, no separators.
`.trim();

const finalPrompt = `${CONSISTENCY_LOCK}\n\n${promptText}`;

const request_body = {
  contents: [
    {
      role: 'user',
      parts: [
        { text: finalPrompt },
        {
          inline_data: {
            mime_type: img_mime,
            data: img_b64
          }
        }
      ]
    }
  ],
  generationConfig: {
    responseModalities: ['IMAGE'],
    imageConfig: {
      aspectRatio: '9:16',
      imageSize: '4K'
    }
  }
};

return {
  json: {
    ...j,
    request_body,
    grid_prompt: finalPrompt,
    person_image_b64: img_b64,
    person_mime_type: img_mime
  }
};

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function getByPath(obj, path) {
  try {
    return path.split('.').reduce((acc, k) => (acc == null ? undefined : acc[k]), obj);
  } catch {
    return undefined;
  }
}

function findInlineImageParts(root) {
  const candidates = root?.candidates;
  if (!Array.isArray(candidates) || !candidates.length) return [];

  const parts = candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts)) return [];

  const imgs = [];
  for (const p of parts) {
    const inline = p?.inline_data || p?.inlineData;
    if (inline?.data) {
      imgs.push({
        b64: inline.data,
        mimeType: inline.mime_type || inline.mimeType || 'image/png'
      });
      continue;
    }
    const fd = p?.fileData;
    if (fd?.fileUri) {
      imgs.push({
        fileUri: fd.fileUri,
        mimeType: fd.mimeType || 'image/png'
      });
    }
  }
  return imgs;
}

function stripDataPrefix(b64) {
  return String(b64 || '').replace(/^data:.*;base64,/, '').trim();
}

const raw = $json || {};
const root = unwrapRoot(raw);
const imageIndex = Number(raw.image_index ?? raw.index ?? 1) || 1;

let imgs = findInlineImageParts(root);

if (!imgs.length) {
  const maybe =
    getByPath(root, 'image.data') ||
    getByPath(root, 'data.image') ||
    getByPath(root, 'output.image') ||
    getByPath(root, 'output.data') ||
    null;

  if (maybe && typeof maybe === 'string') {
    imgs = [{ b64: maybe, mimeType: 'image/png' }];
  }
}

if (!imgs.length) {
  throw new Error('没有在返回体中找到图片数据（inline_data / inlineData）。请检查生图接口实际响应结构。');
}

const first = imgs[0];

if (first.fileUri && !first.b64) {
  throw new Error(`返回的是 fileUri（${first.fileUri}）而不是 base64。需要额外一步去下载该文件再转 binary。`);
}

const mimeType = first.mimeType || 'image/png';
const ext = mimeType.includes('jpeg') || mimeType.includes('jpg') ? 'jpg' : 'png';
const b64 = stripDataPrefix(first.b64);

if (!b64) throw new Error('图片 base64 为空');

return {
  json: {
    ...raw,
    mimeType,
    fileName: `knowledge_card_${imageIndex}.${ext}`
  },
  binary: {
    data: {
      data: b64,
      mimeType,
      fileName: `Product_display_image_${imageIndex}.${ext}`
    }
  }
};

const item = $input.item;
const taskId = $('Webhook').item.json.body.taskId || $('Webhook').item.json.body.task_id || $('Webhook').item.json.body.record_id || 'unknown_task';
const timestamp = Date.now();
const fileName = `${taskId}_grid_${timestamp}.png`;
const publicBase = 'https://YOUR_SUPABASE_PUBLIC_DOMAIN/storage/v1/object/public/images/storyboard';
const publicUrl = `${publicBase}/${fileName}`;

return {
  json: {
    ...($json || {}),
    fileName: fileName,
    taskId: taskId,
    storyboard_image_url: publicUrl
  },
  binary: {
    data: item.binary.data
  }
};

const inputBody = $('Webhook').item.json.body || {};
const script = inputBody.script || inputBody.scriptContent || inputBody.story_text || '';
const contentType = inputBody.content_type || 'ugc带货';

if (!script) {
  throw new Error('Missing script / scriptContent / story_text');
}

const itemIndex = 0;
const binaryPropertyName = 'data';

// 读取真正的二进制 buffer
const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, binaryPropertyName);

if (!buffer || !buffer.length) {
  throw new Error('参考图 buffer 为空，下载图片节点可能没有拿到文件');
}

// 取 binary 元信息
const item = $input.first();
const binaryMeta = item?.binary?.[binaryPropertyName] || {};

return {
  json: {
    story_text: script,
    person_image_b64: buffer.toString('base64'),
    person_mime_type: binaryMeta.mimeType || 'image/jpeg',
    content_type: contentType,
    taskId: inputBody.taskId || inputBody.task_id || inputBody.record_id || 'unknown_task',
    record_id: inputBody.record_id || '',
    table_link: inputBody.table_link || '',
    app_token: inputBody.app_token || '',
    table_id: inputBody.table_id || '',
    tenant_access_token: inputBody.tenant_access_token || '',
    api_key: inputBody.api_key || '',
    app_id: inputBody.app_id || '',
    app_secret: inputBody.app_secret || '',
    workflow_id: inputBody.workflow_id || 'flow_storyboard',
    imageUrl: inputBody.imageUrl || inputBody.referenceImage || ''
  }
};

